 * 3) recall-eval harness (latency buckets, relevance >= 0.82)
 * ════════════════════════════════════════════════════════════════════════ */

describe('recall-eval harness', () => {
  const corpus: EvalDoc[] = Array.from({ length: 12 }, (_, i) => ({
