      mkItem('m4', 100, 0.6),
      mkItem('m5', 100, 0.5),
    ].map((it) => ({ ...it, kind: 'note', title: it.id, content: 'xx '.repeat(it.tokenCost * 4), tags: [], importance: it.score, source: 's', updatedAt: now }));

