describe('p2p-swarm — peer discovery & gossip', () => {
  it('discovers peers from bootstrap hosts and marks them active', () => {
    P2P.peerDiscovery(['127.0.0.1:7100', '127.0.0.1:7101']);
    const peers = P2P.getPeers();
    expect(peers.length).toBe(2);
    for (const p of peers) {
      expect(p.status).toBe('active');
      expect(p.host).toMatch(/127\.0\.0\.1/);
      expect(typeof p.port).toBe('number');
    }
  });

  it('re-discovery reactivates a stale/unreachable peer', () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    const first = P2P.getPeers()[0];
    const before = first.lastSeen;
    first.status = 'unreachable';
    P2P.peerDiscovery(['127.0.0.1:7100']);
    const after = P2P.getPeers()[0];
    expect(after.status).toBe('active');
    expect(after.lastSeen).toBeGreaterThanOrEqual(before);
  });

  it('marks stale peers unreachable during the discovery sweep', () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    P2P.getPeers()[0].lastSeen = Date.now() - 200_000;
    P2P.peerDiscovery([]); // empty bootstrap still runs the stale sweep
    expect(P2P.getPeers()[0].status).toBe('unreachable');
  });

  it('emits peer_found and peer_lost events', () => {
    const found: string[] = [];
    const lost: string[] = [];
    P2P.events.on('p2p:peer_found', (p: any) => found.push(p.id));
    P2P.events.on('p2p:peer_lost', (id: string) => lost.push(id));
    P2P.peerDiscovery(['127.0.0.1:7100']);
    expect(found.length).toBe(1);
    P2P.getPeers()[0].lastSeen = Date.now() - 200_000;
    P2P.peerDiscovery([]);
    expect(lost.length).toBe(1);
  });

  it('publish fans out to every active peer over the mock transport', async () => {
    P2P.peerDiscovery(['127.0.0.1:7100', '127.0.0.1:7101']);
    await P2P.publish('topic-x', 'payload-y');
    expect(fetchMock).toHaveBeenCalledTimes(2);
    const urls = fetchMock.mock.calls.map((c: any) => c[0] as string);
    expect(urls.every((u: string) => u.includes('/api/v1/p2p/message'))).toBe(true);
    const bodies = fetchMock.mock.calls.map((c: any) => JSON.parse((c[1] as RequestInit).body as string));
    expect(bodies.every((b: any) => b.topic === 'topic-x' && b.data === 'payload-y')).toBe(true);
  });

  it('skips unreachable peers when publishing', async () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    P2P.getPeers()[0].status = 'unreachable';
    await P2P.publish('t', 'd');
    expect(fetchMock).not.toHaveBeenCalled();
  });

  it('does not crash when a peer transport rejects', async () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    fetchMock.mockRejectedValueOnce(new Error('network down'));
    await expect(P2P.publish('t', 'd')).resolves.toBeUndefined();
    expect(fetchMock).toHaveBeenCalledTimes(1);
  });

  it('broadcastAuditRoot delegates to publish with the audit_checkpoint topic', async () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    await P2P.broadcastAuditRoot('ROOT', 'CP');
    expect(fetchMock).toHaveBeenCalledTimes(1);
    const body = JSON.parse((fetchMock.mock.calls[0][1] as RequestInit).body as string);
    expect(body.topic).toBe('audit_checkpoint');
    expect(JSON.parse(body.data)).toEqual({ root: 'ROOT', checkpointId: 'CP' });
  });

  it('receiveMessageHandler parses and emits a message event', () => {
    const msgs: any[] = [];
    P2P.events.on('p2p:message', (m: any) => msgs.push(m));
    const res = P2P.receiveMessageHandler({ from: 'peer-a', topic: 't', data: 'd', timestamp: 123 });
    expect(res.ok).toBe(true);
    expect(msgs.length).toBe(1);
    expect(msgs[0].from).toBe('peer-a');
  });

  it('receiveMessageHandler ignores malformed envelopes', () => {
    const msgs: any[] = [];
    P2P.events.on('p2p:message', (m: any) => msgs.push(m));
    const res = P2P.receiveMessageHandler({ foo: 'bar' });
    expect(res.ok).toBe(true);
    expect(msgs.length).toBe(0);
  });

  it('getPeerListHandler returns the current peers', () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    const { peers } = P2P.getPeerListHandler();
    expect(peers.length).toBe(1);
  });

  it('reset clears all peers and identity', () => {
    P2P.peerDiscovery(['127.0.0.1:7100']);
    P2P.reset();
    expect(P2P.getPeers().length).toBe(0);
  });
});

/**
 * phase15-performance.test.ts — Phase 15 (Performance & Scalability) module coverage.
 * Exercises the performance subsystem: response cache (+ stampede), session offload, slow-query
 * advisor, chunked transfer, warmup scheduler, circuit-breaker pool, event-loop lag, graceful drain.
 */
import { describe, it, expect, vi } from 'vitest';
import { ResponseCache, MemoryKVBackend } from '../src/services/performance/response-cache.js';
import {
  InMemorySessionStore,
  RedisSessionStore,
  SessionManager,
  KernelNodePool,
} from '../src/services/performance/redis-session.js';
import { SlowQueryAdvisor, normalizeSql } from '../src/services/performance/slow-query-advisor.js';
import {
  planChunks,
  adaptiveChunkSize,
  contentKindFromType,
  chunkBuffer,
} from '../src/services/performance/chunked-transfer.js';
import { WarmupScheduler } from '../src/services/performance/warmup-scheduler.js';
import { CircuitBreakerPool } from '../src/services/performance/circuit-breaker-pool.js';
import { EventLoopLagMonitor } from '../src/services/performance/event-loop-lag.js';
import { DrainCoordinator } from '../src/services/performance/graceful-drain.js';
import { NodeReplicaRegistry } from '../src/services/performance/registry.js';

describe('response-cache', () => {
  it('stores and retrieves values across tiers', async () => {
    const cache = new ResponseCache(1000, new MemoryKVBackend());
    await cache.set('k1', { a: 1 }, { tags: ['t1'] });
    expect(await cache.get('k1')).toEqual({ a: 1 });
    // L2 path: clear L1 by reaping expired (force via direct delete of L1 is internal; re-get hits L2)
    expect(await cache.get('k1')).toEqual({ a: 1 });
  });

  it('invalidates by tag', async () => {
    const cache = new ResponseCache(1000, new MemoryKVBackend());
    await cache.set('a', 1, { tags: ['x'] });
    await cache.set('b', 2, { tags: ['x', 'y'] });
    const n = await cache.invalidateTags(['x']);
    expect(n).toBe(2);
    expect(await cache.get('a')).toBeUndefined();
    expect(await cache.get('b')).toBeUndefined();
  });

  it('collapses concurrent stampede into a single loader', async () => {
    const cache = new ResponseCache(1000, new MemoryKVBackend());
    let calls = 0;
    const loader = vi.fn(async () => {
      calls++;
      await new Promise((r) => setTimeout(r, 10));
      return 'v';
    });
    const [r1, r2, r3] = await Promise.all([
      cache.getOrLoad('s', loader),
      cache.getOrLoad('s', loader),
      cache.getOrLoad('s', loader),
    ]);
    expect(r1).toBe('v');
    expect(r2).toBe('v');
    expect(r3).toBe('v');
    expect(calls).toBe(1);
    expect(cache.getStats().stampedeCollapsed).toBeGreaterThanOrEqual(2);
  });

  it('reaps expired L1 entries', async () => {
    const cache = new ResponseCache(1, new MemoryKVBackend());
    await cache.set('e', 1);
    await new Promise((r) => setTimeout(r, 5));
    expect(cache.reap()).toBe(1);
  });

  it('clear() wipes both tiers and resets stats', async () => {
    const cache = new ResponseCache(1000, new MemoryKVBackend());
    await cache.set('k1', 'v1');
    const n = await cache.clear();
    expect(n).toBeGreaterThanOrEqual(0);
    const stats = cache.getStats();
    expect(stats.l1Hits + stats.l1Misses + stats.l2Hits + stats.l2Misses).toBe(0);
    expect(await cache.get('k1')).toBeUndefined();
  });

  it('getOrLoad serves fresh value then hits L1', async () => {
    const cache = new ResponseCache(1000, new MemoryKVBackend());
    expect(await cache.getOrLoad('j', () => Promise.resolve({ a: 1 }))).toEqual({ a: 1 });
    expect(await cache.getOrLoad('j', () => Promise.resolve({ a: 2 }))).toEqual({ a: 1 });
  });
});

